fixes.code:
let x: i32 = 42;
let r = &x;
let y = *r; // Dereference the reference

use std::ops::Deref;

struct MyBox<T>(T);

impl<T> Deref for MyBox<T> {
    type Target = T;
    fn deref(&self) -> &T {
        &self.0
    }
}
